 23	import classNames from 'classnames';
 24	import { useForm } from 'react-hook-form';
 25	import * as Yup from 'yup';
 26	import {
 27	  ActionGroup,
 28	  Alert,
 29	  Button,
 30	  Form,
 31	  TextInput,
 32	} from '@patternfly/react-core';
 33	import {
 34	  StoreProviders,
 35	  NOOBAA_TYPE_MAP,
 36	  PROVIDERS_NOOBAA_MAP,
 37	  BUCKET_LABEL_NOOBAA_MAP,
 38	  StoreType,
 39	  providerSchema,
 40	} from '../../constants';
 41	import { NamespaceStoreKind } from '../../types';
 42	import {
 43	  getExternalProviders,
 44	  getProviders,
 45	  secretPayloadCreator,
 46	} from '../../utils';
 47	import { S3EndPointType } from '../mcg-endpoints/s3-endpoint-type';
 48	import {
 49	  initialState,
 50	  providerDataReducer,
 51	  ProviderDataState,
 52	  StoreAction,
 53	} from './reducer';
 54	import '../../style.scss';
 55	import '../mcg-endpoints/noobaa-provider-endpoints.scss';
 56	
 57	const PROVIDERS = getProviders(StoreType.NS);
 58	const externalProviders = getExternalProviders(StoreType.NS);
 59	
 60	type Payload = K8sResourceCommon & {
 61	  spec: {
 62	    type: string;
 63	    [key: string]: any;
 64	  };
 65	};
 66	
 67	type NamespaceStoreFormProps = {
 68	  redirectHandler: (resources?: (NamespaceStoreKind | SecretKind)[]) => void;
 69	  namespace: string;
 70	  className?: string;
 71	  onCancel: () => void;
 72	};
 73	
 74	const createSecret = async (
 75	  dataSourceName: string,
 76	  namespace: string,
 77	  provider: StoreProviders,
 78	  providerDataState: ProviderDataState,
 79	  providerDataDispatch: React.Dispatch<StoreAction>
 80	) => {
 81	  const { secretKey, accessKey } = providerDataState;
 82	  let createdSecret: SecretKind;
 83	  let secretName = dataSourceName.concat('-secret');
 84	  const secretPayload = secretPayloadCreator(
 85	    provider,
 86	    namespace,
 87	    secretName,
 88	    accessKey,
 89	    secretKey
 90	  );
 91	  try {
 92	    createdSecret = (await k8sCreate({
 93	      model: SecretModel,
 94	      data: secretPayload,
 95	    })) as SecretKind;
 96	  } catch {
 97	    secretName = dataSourceName.concat('-');
 98	    const newSecretPayload = {
 99	      ...secretPayload,
100	      metadata: {
101	        generateName: secretName,
102	        namespace: secretPayload.metadata.namespace,
103	      },
104	    };
105	    createdSecret = (await k8sCreate({
106	      model: SecretModel,
107	      data: newSecretPayload,
108	    })) as SecretKind;
109	  } finally {
110	    secretName = createdSecret?.metadata?.name;
111	    providerDataDispatch({ type: 'setSecretName', value: secretName });
112	  }
113	  return secretName;
114	};
115	
116	const NamespaceStoreForm: React.FC<NamespaceStoreFormProps> = (props) => {
117	  const { t } = useCustomTranslation();
118	  const [providerDataState, providerDataDispatch] = React.useReducer(
119	    providerDataReducer,
120	    initialState
121	  );
122	
123	  const [inProgress, setProgress] = React.useState(false);
124	  const [error, setError] = React.useState('');
125	  const [showSecret, setShowSecret] = React.useState(true);
126	
127	  const { onCancel, className, redirectHandler, namespace } = props;
128	
129	  const [data, loaded, loadError] = useSafeK8sList<NamespaceStoreKind>(
130	    NooBaaNamespaceStoreModel,
131	    namespace
132	  );
133	
134	  const { schema, fieldRequirements } = React.useMemo(() => {
135	    const existingNames =
136	      loaded && !loadError ? data?.map((dataItem) => getName(dataItem)) : [];
137	
138	    const fieldRequirements = [
139	      fieldRequirementsTranslations.maxChars(t, 43),
140	      fieldRequirementsTranslations.startAndEndName(t),
141	      fieldRequirementsTranslations.alphaNumericPeriodAdnHyphen(t),
142	      fieldRequirementsTranslations.uniqueName(t, 'NamespaceStore'),
143	    ];
144	
145	    const baseSchema = Yup.object({
146	      'ns-name': Yup.string()
147	        .required()
148	        .max(43, fieldRequirements[0])
149	        .matches(
150	          validationRegEx.startAndEndsWithAlphanumerics,
151	          fieldRequirements[1]
152	        )
153	        .matches(
154	          validationRegEx.alphaNumericsPeriodsHyphensNonConsecutive,
155	          fieldRequirements[2]
156	        )
157	        .test(
158	          'unique-name',
159	          fieldRequirements[3],
160	          (value: string) => !existingNames.includes(value)
161	        ),
162	    });
163	
164	    const schema = baseSchema.concat(providerSchema(showSecret));
165	
166	    return { schema, fieldRequirements };
167	  }, [data, loadError, loaded, showSecret, t]);
168	
169	  const resolver = useYupValidationResolver(schema);
170	  const {
171	    control,
172	    handleSubmit,
173	    watch,
174	    formState: { isValid, isSubmitted },
175	  } = useForm({
176	    ...formSettings,
177	    resolver,
178	  });
179	
180	  const provider = watch('provider-name');
181	
182	  const onSubmit = async (values, event) => {
183	    event.preventDefault();
184	    setProgress(true);
185	    try {
186	      const nsName = values['ns-name'];
187	      const pvc = values['pvc-name'];
188	      const folderName = values['folder-name'];
189	      let { secretName } = providerDataState;
190	      if (!secretName) {
191	        /** Create a secret if secret ==='' */
192	        secretName = await createSecret(
193	          nsName,
194	          namespace,
195	          provider,
196	          providerDataState,
197	          providerDataDispatch
198	        );
199	      }
200	      /** Payload for nss */
201	      const nssPayload: Payload = {
202	        apiVersion: getAPIVersionForModel(NooBaaNamespaceStoreModel as any),
203	        kind: NooBaaNamespaceStoreModel.kind,
204	        metadata: {
205	          namespace,
206	          name: nsName,
207	        },
208	        spec: {
209	          type: NOOBAA_TYPE_MAP[provider],
210	        },
211	      };
212	      if (externalProviders.includes(provider)) {
213	        nssPayload.spec = {
214	          ...nssPayload.spec,
215	          [PROVIDERS_NOOBAA_MAP[provider]]: {
216	            [BUCKET_LABEL_NOOBAA_MAP[provider]]: providerDataState.target,
217	            secret: {
218	              name: secretName,
219	              namespace,
220	            },
221	          },
222	        };
223	      }
224	      switch (provider) {
225	        case StoreProviders.S3:
226	          nssPayload.spec.s3Compatible = {
227	            ...nssPayload.spec.s3Compatible,
228	            endpoint: providerDataState.endpoint,
229	          };
230	          break;
231	        case StoreProviders.IBM:
232	          nssPayload.spec.ibmCos = {
233	            ...nssPayload.spec.ibmCos,
234	            endpoint: providerDataState.endpoint,
235	          };
236	          break;
237	        case StoreProviders.AWS:
238	          nssPayload.spec.awsS3 = {
239	            ...nssPayload.spec.awsS3,
240	            region: providerDataState.region,
241	          };
242	          break;
243	        case StoreProviders.FILESYSTEM:
244	          nssPayload.spec.nsfs = {
245	            ...nssPayload.spec.nsfs,
246	            pvcName: getName(pvc),
247	            subPath: folderName,
248	          };
249	          break;
250	      }
251	
252	      const resources = await k8sCreate({
253	        model: NooBaaNamespaceStoreModel,
254	        data: nssPayload,
255	      });
256	      redirectHandler([resources]);
257	    } catch (submitError) {
258	      setError(submitError.message);
259	    } finally {
260	      setProgress(false);
261	    }
262	  };
263	
264	  return (
265	    <NamespaceSafetyBox>
266	      <Form
267	        className={classNames(
268	          'nb-endpoints-form',
269	          'odf-m-pane__body',
270	          className
271	        )}
272	        onSubmit={handleSubmit(onSubmit)}
273	        noValidate={false}
274	      >
275	        <TextInputWithFieldRequirements
276	          control={control}
277	          fieldRequirements={fieldRequirements}
278	          popoverProps={{
279	            headerContent: t('Name requirements'),
280	            footerContent: `${t('Example')}: my-namespacestore`,
281	          }}
282	          formGroupProps={{
283	            label: t('Namespace store name'),
284	            fieldId: 'namespacestore-name',
285	            className: 'nb-endpoints-form-entry',
286	            isRequired: true,
287	          }}
288	          textInputProps={{
289	            id: 'ns-name',
290	            name: 'ns-name',
291	            'data-test': 'namespacestore-name',
292	            placeholder: 'my-namespacestore',
293	          }}
294	        />
295	
296	        <FormGroupController
297	          name="provider-name"
298	          control={control}
299	          defaultValue={StoreProviders.AWS}
300	          formGroupProps={{
301	            label: t('Provider'),
302	            fieldId: 'provider-name',
303	            className: 'nb-endpoints-form-entry',
304	            isRequired: true,
305	          }}
306	          render={({ value, onChange, onBlur }) => (
307	            <StaticDropdown
308	              className="nb-endpoints-form-entry__dropdown"
309	              onSelect={onChange}
310	              onBlur={onBlur}
311	              dropdownItems={PROVIDERS}
312	              defaultSelection={value}
313	              data-test="namespacestore-provider"
314	              isFullWidth
315	            />
316	          )}
317	        />
318	        {(provider === StoreProviders.AWS ||
319	          provider === StoreProviders.S3 ||
320	          provider === StoreProviders.IBM ||
321	          provider === StoreProviders.AZURE) && (
322	          <S3EndPointType
323	            showSecret={showSecret}
324	            setShowSecret={setShowSecret}
325	            control={control}
326	            type={StoreType.NS}
327	            provider={provider}
328	            namespace={namespace}
329	            state={providerDataState}
330	            dispatch={providerDataDispatch}
331	          />
332	        )}
333	        {provider === StoreProviders.FILESYSTEM && (
334	          <>
335	            <FormGroupController
336	              name="pvc-name"
337	              control={control}
338	              formGroupProps={{
339	                label: t('Persistent volume claim'),
340	                fieldId: 'pvc-name',
341	                className: 'nb-endpoints-form-entry',
342	                isRequired: true,
343	              }}
344	              render={({ onChange, onBlur }) => (
345	                <ResourceDropdown<PersistentVolumeClaimKind>
346	                  id="pvc-name"
347	                  resourceModel={PersistentVolumeClaimModel}
348	                  resource={{
349	                    kind: PersistentVolumeClaimModel.kind,
350	                    isList: true,
351	                    namespace,
352	                  }}
353	                  onSelect={onChange}
354	                  onBlur={onBlur}
355	                  filterResource={(pvcObj: PersistentVolumeClaimKind) =>
356	                    pvcObj?.status?.phase === 'Bound' &&
357	                    pvcObj?.spec?.accessModes.some(
358	                      (mode) => mode === 'ReadWriteMany'
359	                    )
360	                  }
361	                />
362	              )}
363	            />
364	            <FormGroupController
365	              name="folder-name"
366	              control={control}
367	              formGroupProps={{
368	                label: t('Folder'),
369	                fieldId: 'folder-name',
370	                helperText: t(
371	                  'If the name you write exists, we will be using the existing folder if not we will create a new folder '
372	                ),
373	                className: 'nb-endpoints-form-entry',
374	                isRequired: true,
375	              }}
376	              render={({ value, onChange, onBlur }) => (
377	                <TextInput
378	                  id="folder-name"
379	                  onChange={onChange}
380	                  onBlur={onBlur}
381	                  value={value}
382	                  data-test="folder-name"
383	                  placeholder="Please enter the folder name"
384	                />
385	              )}
386	            />
387	          </>
388	        )}
389	        {!isValid && isSubmitted && (
390	          <Alert
391	            variant="danger"
392	            isInline
393	            title={t('Address form errors to proceed')}
394	          />
395	        )}
396	        <ButtonBar errorMessage={error} inProgress={inProgress}>
397	          <ActionGroup>
398	            <Button
399	              type="submit"
400	              data-test="namespacestore-create-button"
401	              variant="primary"
402	            >
403	              {t('Create')}
404	            </Button>
405	            <Button onClick={onCancel} variant="secondary">
406	              {t('Cancel')}
407	            </Button>
408	          </ActionGroup>
409	        </ButtonBar>
410	      </Form>
411	    </NamespaceSafetyBox>
412	  );
413	};
414	
415	export default NamespaceStoreForm;

