293	          }}
294	        />
295	
296	        <FormGroupController
297	          name="provider-name"
298	          control={control}
299	          defaultValue={StoreProviders.AWS}
300	          formGroupProps={{
301	            label: t('Provider'),
302	            fieldId: 'provider-name',
303	            className: 'nb-endpoints-form-entry',
304	            isRequired: true,
305	          }}
306	          render={({ value, onChange, onBlur }) => (
307	            <StaticDropdown
308	              className="nb-endpoints-form-entry__dropdown"
309	              onSelect={onChange}
310	              onBlur={onBlur}
311	              dropdownItems={PROVIDERS}
312	              defaultSelection={value}
313	              data-test="namespacestore-provider"
314	              isFullWidth
315	            />
316	          )}
317	        />
318	        {(provider === StoreProviders.AWS ||
319	          provider === StoreProviders.S3 ||
320	          provider === StoreProviders.IBM ||
321	          provider === StoreProviders.AZURE) && (
322	          <S3EndPointType
323	            showSecret={showSecret}
324	            setShowSecret={setShowSecret}
325	            control={control}
326	            type={StoreType.NS}
327	            provider={provider}
328	            namespace={namespace}
329	            state={providerDataState}
330	            dispatch={providerDataDispatch}
331	          />
332	        )}
333	        {provider === StoreProviders.FILESYSTEM && (
334	          <>
335	            <FormGroupController
336	              name="pvc-name"
337	              control={control}
338	              formGroupProps={{
339	                label: t('Persistent volume claim'),
340	                fieldId: 'pvc-name',
341	                className: 'nb-endpoints-form-entry',
342	                isRequired: true,
343	              }}
344	              render={({ onChange, onBlur }) => (
345	                <ResourceDropdown<PersistentVolumeClaimKind>
346	                  id="pvc-name"
347	                  resourceModel={PersistentVolumeClaimModel}
348	                  resource={{
349	                    kind: PersistentVolumeClaimModel.kind,
350	                    isList: true,
351	                    namespace,
352	                  }}
353	                  onSelect={onChange}
354	                  onBlur={onBlur}
355	                  filterResource={(pvcObj: PersistentVolumeClaimKind) =>
356	                    pvcObj?.status?.phase === 'Bound' &&
357	                    pvcObj?.spec?.accessModes.some(
358	                      (mode) => mode === 'ReadWriteMany'
359	                    )
360	                  }
361	                />
362	              )}
363	            />
364	            <FormGroupController
365	              name="folder-name"
366	              control={control}
367	              formGroupProps={{
368	                label: t('Folder'),
369	                fieldId: 'folder-name',
370	                helperText: t(
371	                  'If the name you write exists, we will be using the existing folder if not we will create a new folder '
372	                ),
373	                className: 'nb-endpoints-form-entry',
374	                isRequired: true,
375	              }}
376	              render={({ value, onChange, onBlur }) => (
377	                <TextInput
378	                  id="folder-name"
379	                  onChange={onChange}
380	                  onBlur={onBlur}
381	                  value={value}
382	                  data-test="folder-name"
383	                  placeholder="Please enter the folder name"
384	                />
385	              )}
386	            />
387	          </>
388	        )}
389	        {!isValid && isSubmitted && (
390	          <Alert
391	            variant="danger"
392	            isInline
393	            title={t('Address form errors to proceed')}
394	          />
395	        )}
396	        <ButtonBar errorMessage={error} inProgress={inProgress}>
397	          <ActionGroup>
398	            <Button
399	              type="submit"
400	              data-test="namespacestore-create-button"
401	              variant="primary"
402	            >
403	              {t('Create')}
404	            </Button>
405	            <Button onClick={onCancel} variant="secondary">
406	              {t('Cancel')}
407	            </Button>
408	          </ActionGroup>
409	        </ButtonBar>
410	      </Form>
411	    </NamespaceSafetyBox>
412	  );
413	};
414	
415	export default NamespaceStoreForm;

